import{_ as o,o as e,c as n,ac as a}from"./chunks/framework.DnBnwVZk.js";const d=JSON.parse('{"title":"Dubbo源码-框架初始化","description":"","frontmatter":{"date":"2020-04-02T00:00:00.000Z","categories":["Dubbo"],"tags":["Dubbo","源码"]},"headers":[],"relativePath":"views/java/dubbo/2020/DubboInit.md","filePath":"views/java/dubbo/2020/DubboInit.md","lastUpdated":1775654397000}'),t={name:"views/java/dubbo/2020/DubboInit.md"};function r(l,i,s,p,b,c){return e(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1585785600000"},[...i[0]||(i[0]=[a(`<h1 id="dubbo源码-框架初始化" tabindex="-1">Dubbo源码-框架初始化 <a class="header-anchor" href="#dubbo源码-框架初始化" aria-label="Permalink to &quot;Dubbo源码-框架初始化&quot;">​</a></h1><p>Dubbo通过利用Spring的生命周期钩子、监听器等机制来初始化及构造自己的配置。</p><h2 id="_1-自定义springboot生命周期类" tabindex="-1">1. 自定义SpringBoot生命周期类 <a class="header-anchor" href="#_1-自定义springboot生命周期类" aria-label="Permalink to &quot;1. 自定义SpringBoot生命周期类&quot;">​</a></h2><h3 id="_1-1-applicationlistener" tabindex="-1">1.1 ApplicationListener <a class="header-anchor" href="#_1-1-applicationlistener" aria-label="Permalink to &quot;1.1 ApplicationListener&quot;">​</a></h3><ul><li>OverrideDubboConfigApplicationListener：负责加载Dubbo配置，优先级： <ol><li>Spring管理的配置</li><li>Spring配置中dubbo.properties.file定义的文件内部的配置</li><li>系统环境变量中配置的dubbo.properties.file定义的文件内部的配置</li></ol></li><li>DubboConfigBeanDefinitionConflictApplicationListener：负责确保上下文中只有一个org.apache.dubbo.config.ApplicationConfig类型的Bean</li><li>WelcomeLogoApplicationListener：展示Logo页面</li><li>AwaitingNonWebApplicationListener：判断当前是否是WEB环境(通过ApplicationContext类型判断),并在非WEB环境下阻塞，保证程序唤醒</li></ul><h3 id="_1-2-applicationcontextinitializer" tabindex="-1">1.2 ApplicationContextInitializer <a class="header-anchor" href="#_1-2-applicationcontextinitializer" aria-label="Permalink to &quot;1.2 ApplicationContextInitializer&quot;">​</a></h3><p>DubboApplicationContextInitializer：SpringApplication实例初始化过程中调用，向上下文注入自定义的BeanFactoryPostProcessor：OverrideBeanDefinitionRegistryPostProcessor类</p><h3 id="_1-3-environmentpostprocessor" tabindex="-1">1.3 EnvironmentPostProcessor <a class="header-anchor" href="#_1-3-environmentpostprocessor" aria-label="Permalink to &quot;1.3 EnvironmentPostProcessor&quot;">​</a></h3><p>DubboDefaultPropertiesEnvironmentPostProcessor：读取application.name等信息，并写入自定义的PropertySource到Environment,主要是在Properties里加入或替换默认配置,名称为&quot;defaultProperties&quot;，2.7.5版本是以下4个： - dubbo.application.name：默认取spring.application.name配置 - dubbo.config.multiple：默认true - dubbo.application.qos-enable：默认false - spring.main.allow-bean-definition-overriding：默认true，即允许BeanOverride=</p><h2 id="_2-利用autoconfiguration机制注入bean、beandefinition、beanfactorypostprocessor" tabindex="-1">2. 利用AutoConfiguration机制注入Bean、BeanDefinition、BeanFactoryPostProcessor <a class="header-anchor" href="#_2-利用autoconfiguration机制注入bean、beandefinition、beanfactorypostprocessor" aria-label="Permalink to &quot;2. 利用AutoConfiguration机制注入Bean、BeanDefinition、BeanFactoryPostProcessor&quot;">​</a></h2><h3 id="_2-1-autoconfiguration导入配置类直接定义bean" tabindex="-1">2.1 AutoConfiguration导入配置类直接定义Bean <a class="header-anchor" href="#_2-1-autoconfiguration导入配置类直接定义bean" aria-label="Permalink to &quot;2.1 AutoConfiguration导入配置类直接定义Bean&quot;">​</a></h3><ul><li>DubboRelaxedBinding2AutoConfiguration： <ul><li>PropertyResolver:注册dubbo.scan.开头的property</li><li>ConfigurationBeanBinder:BinderDubboConfigBinder</li></ul></li><li>DubboAutoConfiguration <ul><li>ServiceAnnotationBeanPostProcessor：需要定义dubbo.scan.base-packages</li><li>ReferenceAnnotationBeanPostProcessor</li><li>SingleDubboConfigConfiguration:单配置情况下：允许通过properties文件来定义bean，比如dubbo.application=com.my.DubboAppConfig</li><li>MultipleDubboConfigConfiguration:多配置情况下：同上</li><li>PropertyResolver：指向默认的Environment</li></ul></li><li>DubboRelaxedBindingAutoConfiguration:SpringBoot1.X用，已废弃</li></ul><h3 id="_2-2-通过-import自定义的beanregistrar来注册框架bean" tabindex="-1">2.2 通过@Import自定义的BeanRegistrar来注册框架Bean <a class="header-anchor" href="#_2-2-通过-import自定义的beanregistrar来注册框架bean" aria-label="Permalink to &quot;2.2 通过@Import自定义的BeanRegistrar来注册框架Bean&quot;">​</a></h3><p>@EnableDubbo注解作为Dubbo的根注解，其中Import了以下的Registrar</p><ul><li>DubboConfigConfigurationRegistrar： <ol><li>注册Bean:DubboConfigConfiguration.Single或者MultipleBean</li><li>注册Bean:DubboConfigAliasPostProcessor</li><li>注册Bean:NamePropertyDefaultValueDubboConfigBeanCustomizer</li></ol></li><li>DubboComponentScanRegistrar: <ol><li>处理@DubboComponentScan定义的package,如果没有定义，则默认取mainClass的包名</li><li>注册INFRA_Bean:ServiceAnnotationBeanPostProcessor,后续处理@Service注解，构造器参数中的basePackages为上一步处理的结果</li><li>注解INFRA_Bean:ReferenceAnnotationBeanPostProcessor</li></ol></li><li>DubboConfigBindingRegistrar <ol><li>处理@EnableDubboConfigBinding注解定义的自定义的Dubbo配置文件前缀</li></ol></li><li>DubboLifecycleComponentRegistrar <ol><li>注册DubboLifecycleComponentApplicationListener，此类负责加载自定义的DubboComponent生命周期钩子类：<code>org.apache.dubbo.common.context.Lifecycle</code></li><li>注册DubboBootstrapApplicationListener，此类负责在Context开启和关闭时调用<strong>DubboBootstrap</strong>中的生命周期钩子</li></ol></li><li>ConfigurationBeanBindingRegistrar <ol><li>注册DubboConfigBean：根据properties定义的dubbo.xxx来初始化对应的ConfigBean</li><li>注册Bean：ConfigurationBeanBindingPostProcessor</li></ol></li></ul><h3 id="_2-3-自定义的beandefinitionregistrypostprocessor-介入beandefinition过程" tabindex="-1">2.3 自定义的BeanDefinitionRegistryPostProcessor:介入BeanDefinition过程 <a class="header-anchor" href="#_2-3-自定义的beandefinitionregistrypostprocessor-介入beandefinition过程" aria-label="Permalink to &quot;2.3 自定义的BeanDefinitionRegistryPostProcessor:介入BeanDefinition过程&quot;">​</a></h3><ul><li>DubboConfigAliasPostProcessor:负责在Dubbo相关的ConfigBean注册后，把ID注册成Bean的别名</li><li>ServiceAnnotationBeanPostProcessor： <ul><li>注册DubboBootstrapApplicationListener：@EnableDubbo已经注册了这个Listener</li><li>扫描指定的package下面的所有类，获得Dubbo@Service注解后的类，并注册成BeanDefinition： 1. 通过调用Spring提供的方法，指定注解扫描 2. 获取Interface，注意这里支持三种模式，1. 注解定义Class，2.注解定义interface全限定名，3.根据继承来定义,<strong>注意，Dubbo只会提取第一个interface</strong> 3. 处理对应的Bean中@Service注解内部的attribute： - provider - monitor - application - module - registry:指定注册中心配置类 - protocol 4. BeanName为<code>ServiceBean:接口名:version:group</code> 5. BeanDefinition会被BeanPostProcessor处理复制成Dubbo的ServiceBean，复制后的大部分属性跟Spring扫描出来的bd相同，区别是增加了protocol等dubbo特有属性，而且class被设置成了ServiceBean！，这些ServiceBean在初始化过程中，由于附录1中的代码，会在构造完成后把自己注册到configManager中：</li></ul></li></ul><p>附录1 ServiceBean把自己注册到ConfigManager中</p><div class="language-java vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  @</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">PostConstruct</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> addIntoConfigManager</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      ApplicationModel.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getConfigManager</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">addConfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span></code></pre></div><h3 id="_2-4-自定义的beanfacotrypostprocessor" tabindex="-1">2.4 自定义的BeanFacotryPostProcessor <a class="header-anchor" href="#_2-4-自定义的beanfacotrypostprocessor" aria-label="Permalink to &quot;2.4 自定义的BeanFacotryPostProcessor&quot;">​</a></h3><ul><li>ConfigurationBeanBindingPostProcessor:加载两个BeanPostProcessor <ul><li>ConfigurationBeanBinder</li><li>ConfigurationBeanCustomizer：为bean注入name属性</li></ul></li></ul><h2 id="_3-自定义的beanpostprocessor在bean创建过程介入" tabindex="-1">3. 自定义的BeanPostProcessor在Bean创建过程介入 <a class="header-anchor" href="#_3-自定义的beanpostprocessor在bean创建过程介入" aria-label="Permalink to &quot;3. 自定义的BeanPostProcessor在Bean创建过程介入&quot;">​</a></h2><ul><li>ConfigurationBeanBindingPostProcessor: <ul><li>BeforeInitialization:把PropertySource内部的配置绑定到对应的配置类的Field中，并且调用ConfigurationBeanCustomizer注入Name</li></ul></li><li>ReferenceAnnotationBeanPostProcessor: <ul><li>在Bean实例初始化后，populateBean阶段，调用到postProcessPropertyValues方法： <ol><li>查找@Reference注解，获取注解配置信息</li><li>根据注解构造一个ReferenceBean,这个Bean里保存了后续生成代理所需要的必要属性信息，比如version等</li><li>把上面的ReferenceBean注入到@Reference注解对应的Field中</li><li>创建代理：Invoker，根据Protocol对应的实例，默认使用RegistryProtocol，调用其refer方法，见<a href="./DubboRPC.html">Dubbo RPC 源码解析</a></li></ol></li></ul></li></ul><h2 id="_4-自定义的事件监听-在上下文事件中处理并启动dubbo" tabindex="-1">4. 自定义的事件监听，在上下文事件中处理并启动Dubbo <a class="header-anchor" href="#_4-自定义的事件监听-在上下文事件中处理并启动dubbo" aria-label="Permalink to &quot;4. 自定义的事件监听，在上下文事件中处理并启动Dubbo&quot;">​</a></h2><ul><li>DubboLifecycleComponentApplicationListener： <ul><li>ContextRefreshedEvent：加载所有Dubbo的Lifecycle类到缓存，并调用其start方法，默认实现没有Lifecycle实现类</li></ul></li><li>DubboBootstrapApplicationListener： <ul><li>ContextRefreshedEvent：加载DubboBootStrap类，调用dubboBootstrap的start方法，<strong>这是Dubbo的核心类和核心方法</strong></li></ul></li></ul><h2 id="_5-applicationmodel" tabindex="-1">5. ApplicationModel <a class="header-anchor" href="#_5-applicationmodel" aria-label="Permalink to &quot;5. ApplicationModel&quot;">​</a></h2><ol><li>Bean初始化阶段，初始化ConfigManger对象内部的各种Config: <ul><li>ApplicationConfig: 保存Application级别的配置</li><li>RegistryConfig: 注册中心配置</li><li>Protocol：序列化配置</li><li>ProviderConfig:</li><li><strong>ServiceBean</strong>：注意，所有的Service，都是以ServiceBean的形式存在Spring的工厂里，ServiceBean内存存储了每个Service的元信息</li><li>ConfigCenter:配置中心</li><li>Monitor：监视器</li><li>Metric:指标</li><li>Module:</li><li>SSL</li></ul></li></ol>`,27)])])}const g=o(t,[["render",r]]);export{d as __pageData,g as default};
